  final AwsCredential awsCredential = AwsCredential('AKIAIOSFODNN7EXAMPLE', 'wJalrXUtnFEMI/K7MDENG/bPxRfiCYEXAMPLEKEY');
  final Region region = Region.usWest2;
  final S3 s3 = S3(awsCredential, region: region);

  Future<void> uploadToS3() async {
    var bucket = 'your-bucket-name';
    var keyName = DateTime.now().toString() + '.jpg';
    var file = File(imagePath);
    var putRequest = PutObjectRequest()
      ..bucket = bucket
      ..key = keyName
      ..contentType = MimeTypeUtils.getMimeTypeFromFile(file)
